#usda 1.0
(
    defaultPrim = "Assets"
)

def Xform "Assets"
{
    def Xform "Chair" (
        variants = {
            string modelVariant = "simple"
        }
        prepend variantSets = "modelVariant"
    )
    {
        variantSet "modelVariant" = {
            "detailed" {
                def Cube "Geo"
                {
                    uniform token purpose = "default"
                }

            }
            "simple" {
                def Cube "Geo"
                {
                    uniform token purpose = "default"
                }

            }
        }
    }
}

#usda 1.0
(
    defaultPrim = "Shot"
    subLayers = [
        @./assets.usda@
    ]
)

def Xform "Shot"
{
    def Xform "Set"
    {
        def Xform "ChairA" (
            prepend references = @./assets.usda@</Assets/Chair>
        )
        {
            custom float3 xformOp:translate = (-2, 0, 0)
        }

        def Xform "ChairB" (
            prepend references = @./assets.usda@</Assets/Chair>
        )
        {
            custom float3 xformOp:translate = (2, 0, 0)
        }
    }

    def Xform "Lighting" (
        variants = {
            string lightingVariant = "day"
        }
        prepend variantSets = "lightingVariant"
    )
    {
        variantSet "lightingVariant" = {
            "day" {
                def DistantLight "Sun"
                {
                    float inputs:intensity = 50000
                }

            }
            "night" {
                def DomeLight "Sky"
                {
                    float inputs:intensity = 500
                }

            }
        }
    }
}
